import { useEffect, useState } from "react";
import Home from "../Home";

export default function ThreadSection({
                                          title = "Threads",
                                          width,
                                          showAddButton = false,
                                          onAddThread
                                      }) {
    const [threads, setThreads] = useState([]);
    const [hoveredId, setHoveredId] = useState(null);

    useEffect(() => {
        fetch("/api/threads")
            .then(r => r.json())
            .then(setThreads)
            .catch(() => setThreads([]));
    }, []);

    const boxHover = {
        transform: "translateY(-2px)",
        boxShadow: "0 6px 16px rgba(0,0,0,0.25)",
        backgroundColor: "#cac7c7"
    };

    return (
        <div style={{ width, display: "flex", flexDirection: "column" }}>
            {showAddButton && (
                <button className={"add-btn"} onClick={onAddThread}>
                    Add Thread
                </button>
            )}

            <h3 className={"col-title"}>{title}</h3>

            {threads.map(thread => (
                <div
                    key={thread.id}
                    className={"threads"}
                    style={{
                        ...(hoveredId === thread.id ? boxHover : {})
                    }}
                    onMouseEnter={() => setHoveredId(thread.id)}
                    onMouseLeave={() => setHoveredId(null)}
                    onClick={() => {
                        window.location.hash = `#/thread/${thread.id}`;
                    }}
                >
                    <div style={{display: "flex", flexDirection: "column"}}>
                        <span style={{fontWeight: 600}}>
                            {thread.title}
                        </span>
                        <span style={{fontSize: "0.75rem", opacity: 0.7}}>
                            {thread.published &&
                                new Date(thread.published).toLocaleDateString()}
                            {thread.author && ` · ${thread.author}`}
                        </span>
                    </div>
                </div>
            ))}
            {/* Thread Modal */}
            {showThreadModal && (
                <div style={styles.ThreadWindow}>
                    <div style={styles.ThreadContent}>
                        <h3>Add New Thread</h3>
                        <form onSubmit={handleThreadSubmit}>
                            <input
                                name="title"
                                placeholder="Thread Title"
                                value={newThread.title}
                                onChange={handleThreadChange}
                                required
                                style={styles.input}
                            />
                            <textarea
                                name="content"
                                placeholder="Thread Content"
                                value={newThread.content}
                                onChange={handleThreadChange}
                                required
                                style={styles.textarea}
                            />
                            <button type="submit" style={styles.submitBtn}>Save Thread</button>
                            <button type="button" onClick={() => setShowThreadModal(false)} style={styles.cancelBtn}>Cancel</button>
                        </form>
                    </div>
                </div>
            )}

        </div>


    );
}
